// src/context/AuthContext.js
import React, { createContext, useState, useContext, useEffect } from 'react';
import { authService } from '../services/authService';
import { toast } from 'react-toastify';

const AuthContext = createContext(null);

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  useEffect(() => {
    const token = localStorage.getItem('token');
    console.log('AuthProvider - Token found:', !!token);
    if (token) {
      const userData = authService.getCurrentUser();
      if (userData) {
        console.log('AuthProvider - Raw userData:', userData);
        
        // ⭐ FIX: Ensure roles are properly set from multiple possible sources
        const userWithRoles = {
          ...userData,
          roles: userData.roles || userData.authorities || userData.role || []
        };
        
        // If roles is a string (like "ROLE_ADMIN"), convert to array
        if (typeof userWithRoles.roles === 'string') {
          userWithRoles.roles = [{ name: userWithRoles.roles }];
        }
        
        // If roles is an array of strings, convert to array of objects
        if (Array.isArray(userWithRoles.roles) && typeof userWithRoles.roles[0] === 'string') {
          userWithRoles.roles = userWithRoles.roles.map(name => ({ name }));
        }
        
        console.log('AuthProvider - Processed user:', userWithRoles);
        console.log('AuthProvider - Roles:', userWithRoles.roles);
        
        setUser(userWithRoles);
        setIsAuthenticated(true);
      } else {
        console.warn('AuthProvider - No user data, logging out');
        authService.logout();
      }
    } else {
      console.warn('AuthProvider - No token found');
    }
    setLoading(false);
  }, []);

  const login = async (username, password) => {
    try {
      console.log('Attempting login for:', username);
      const data = await authService.login(username, password);
      console.log('Login response:', data);
      
      if (data.token) {
        // ⭐ FIX: Ensure roles are properly set
        let userRoles = data.roles || data.authorities || data.role || [];
        
        // If roles is a string, convert to array
        if (typeof userRoles === 'string') {
          userRoles = [{ name: userRoles }];
        }
        
        // If roles is an array of strings, convert to array of objects
        if (Array.isArray(userRoles) && typeof userRoles[0] === 'string') {
          userRoles = userRoles.map(name => ({ name }));
        }
        
        const userData = {
          ...data,
          roles: userRoles
        };
        
        console.log('Login - Processed user data:', userData);
        
        localStorage.setItem('token', data.token);
        localStorage.setItem('user', JSON.stringify(userData));
        setUser(userData);
        setIsAuthenticated(true);
        toast.success('Login successful!');
        return { success: true, user: userData };
      } else {
        throw new Error('No token received');
      }
    } catch (error) {
      console.error('Login error:', error);
      const errorMsg = error.response?.data?.error || error.message || 'Login failed';
      toast.error(errorMsg);
      return { success: false, error: errorMsg };
    }
  };

  const logout = () => {
    authService.logout();
    setUser(null);
    setIsAuthenticated(false);
    toast.info('Logged out successfully');
  };

  // Helper function to check if user has a specific role
  const hasRole = (roleName) => {
    if (!user) {
      console.warn('hasRole - No user found');
      return false;
    }
    const roles = user.roles || [];
    console.log('hasRole - Checking for', roleName, 'in', roles);
    const hasRole = roles.some(role => {
      const roleNameValue = typeof role === 'string' ? role : role.name;
      return roleNameValue === roleName;
    });
    console.log('hasRole - Result:', hasRole);
    return hasRole;
  };

  // Helper function to check if user is admin
  const isAdmin = () => {
    const result = hasRole('ROLE_ADMIN');
    console.log('isAdmin - Result:', result);
    return result;
  };

  return (
    <AuthContext.Provider
      value={{
        user,
        login,
        logout,
        isAuthenticated,
        loading,
        hasRole,
        isAdmin,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};
